def validate_research_axis(axis, known_decisions):
    problems = []

    # A5: C-TOTALITY - ensure axis is a dict
    if not isinstance(axis, dict):
        return {"ok": False, "problems": ["axis must be a dict"]}

    # A1: Check all listed fields are present
    required_fields = ["axis_id", "supports_decisions", "required", "safe_behavior_if_unknown", "rdec_ref"]
    for field in required_fields:
        if field not in axis:
            problems.append(f"missing required field: {field}")

    if problems:
        return {"ok": False, "problems": problems}

    # A2: Check supports_decisions is a non-empty list and all elements are in known_decisions
    supports_decisions = axis["supports_decisions"]
    if not isinstance(supports_decisions, list) or len(supports_decisions) == 0:
        problems.append("supports_decisions must be a non-empty list")
    else:
        for decision_id in supports_decisions:
            if decision_id not in known_decisions:
                problems.append(f"decision '{decision_id}' in supports_decisions is not in known_decisions")

    # A3: Check safe_behavior_if_unknown is a non-empty string
    safe_behavior = axis["safe_behavior_if_unknown"]
    if not isinstance(safe_behavior, str) or len(safe_behavior) == 0:
        problems.append("safe_behavior_if_unknown must be a non-empty string")

    # A4: If required is True, rdec_ref must be a non-empty string
    if axis["required"] is True:
        rdec_ref = axis["rdec_ref"]
        if not isinstance(rdec_ref, str) or len(rdec_ref) == 0:
            problems.append("rdec_ref must be a non-empty string when required is True")

    return {"ok": len(problems) == 0, "problems": problems}
